<script setup lang="ts">
import { computed, ref, toRef } from 'vue'
import { PhX } from '@phosphor-icons/vue'
import { useModalLifecycle } from './useModalLifecycle'
const props=defineProps<{ open: boolean; title: string; eyebrow?: string; labelledBy?: string }>(); const emit=defineEmits<{ close: [] }>(); const panel=ref<HTMLElement|null>(null); const titleId=computed(()=>props.labelledBy??`mobile-sheet-${props.title.toLowerCase().replace(/[^a-z0-9]+/g,'-')}`); useModalLifecycle(toRef(props,'open'),panel,()=>emit('close'))
</script>
<template><Teleport to="body"><section v-if="open" ref="panel" class="mobile-sheet" role="dialog" aria-modal="true" :aria-labelledby="titleId"><header class="mobile-sheet__header"><div><p v-if="eyebrow" class="eyebrow">{{eyebrow}}</p><h2 :id="titleId">{{title}}</h2></div><button type="button" data-autofocus aria-label="Close" @click="$emit('close')"><PhX :size="24" weight="bold" aria-hidden="true"/></button></header><div class="mobile-sheet__body"><slot/></div></section></Teleport></template>
<style scoped>.mobile-sheet{position:fixed;z-index:40;inset:0;overflow-y:auto;overscroll-behavior:contain;color:var(--casa-ink);background:var(--casa-background)}.mobile-sheet__header{position:sticky;z-index:2;top:0;min-height:calc(var(--app-bar-height) + var(--safe-top));display:flex;align-items:center;justify-content:space-between;gap:1rem;padding:var(--safe-top) 1rem 0;border-bottom:1px solid var(--casa-border);background:rgb(255 252 247 / 97%);backdrop-filter:blur(14px)}.mobile-sheet__header h2{margin:.1rem 0 .5rem;font-family:var(--font-display);font-size:1.65rem}.mobile-sheet__header button{width:48px;min-width:48px;height:48px;display:grid;place-items:center;border:1px solid var(--casa-border);border-radius:999px;color:var(--casa-deep-palm);background:#fff}.mobile-sheet__body{width:min(100%,44rem);display:grid;gap:1rem;margin:auto;padding:1rem 1rem max(1.5rem,var(--safe-bottom))}.mobile-sheet__body :deep(form){display:grid;gap:1rem;padding-bottom:4.5rem}.mobile-sheet__body :deep(form>button.primary:last-child){position:sticky;bottom:calc(var(--safe-bottom) + .5rem);z-index:4;box-shadow:var(--shadow-float)}.mobile-sheet__body :deep(form>button.primary:last-child:disabled){opacity:1;color:#fff;background:#8d9d8b}.mobile-sheet__body :deep(.detail){display:grid;gap:1rem}.mobile-sheet__body :deep(.detail>section),.mobile-sheet__body :deep(form.editor){padding:1rem;border:1px solid var(--casa-border);border-radius:var(--radius-operation);background:var(--casa-paper)}@media(min-width:640px){.mobile-sheet__body :deep(form.editor){grid-template-columns:repeat(2,minmax(0,1fr))}.mobile-sheet__body :deep(form.editor>button.primary),.mobile-sheet__body :deep(form.editor>fieldset),.mobile-sheet__body :deep(form.editor>.alert){grid-column:1/-1}}</style>
